import { Component, OnInit, ElementRef, ViewChild, AfterViewInit } from '@angular/core';
import { Chessground } from 'chessground';
import { Chess } from 'chess.js';
import { ChessAgentService } from '../../services/chess-agent.service';
import { Api } from 'chessground/api';
import { Key } from 'chessground/types';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit, AfterViewInit {
  @ViewChild('chessBoardContainer', { static: false }) chessBoardContainer!: ElementRef;

  private cgApi!: Api;
  private chessGame = new Chess();

  currentFen: string = this.chessGame.fen();
  aiAnalysis: string = "Déplacez une pièce ou posez une question au Grand Maître FFE...";
  errorMessage: string = "";
  userInput: string = '';
  isLoading: boolean = false;

  constructor(private agentService: ChessAgentService) {}

  ngOnInit(): void {}

  ngAfterViewInit(): void {
    this.initChessground();
  }

  /**
   * Initialise l'interface graphique Chessground et configure les callbacks de mouvements
   */
  private initChessground(): void {
    this.cgApi = Chessground(this.chessBoardContainer.nativeElement, {
      fen: this.currentFen,
      movable: {
        color: 'white',
        free: false,
        dests: this.getValidMoves()
      },
      events: {
        move: (orig, dest) => this.handlePieceMove(orig, dest)
      }
    });
  }

  /**
   * Gère le déplacement d'une pièce sur l'échiquier
   */
  private handlePieceMove(orig: string, dest: string): void {
    try {
      this.chessGame.move({ from: orig, to: dest, promotion: 'q' });
      this.currentFen = this.chessGame.fen();
      this.errorMessage = "";
      this.isLoading = true;

      this.agentService.analyzePosition(this.currentFen).subscribe({
        next: (res: any) => {
          this.aiAnalysis = res.response;
          this.isLoading = false;
          this.updateBoardState();
        },
        error: (err: any) => {
          console.error("Erreur d'analyse :", err);
          this.errorMessage = "L'agent n'a pas pu analyser cette position.";
          this.isLoading = false;
          this.updateBoardState();
        }
      });
    } catch (e) {
      this.cgApi.set({ fen: this.currentFen });
    }
  }

  /**
   * Met à jour les coups légaux possibles pour le joueur suivant
   */
  private updateBoardState(): void {
    const nextColor = this.chessGame.turn() === 'w' ? 'white' : 'black';
    this.cgApi.set({
      turnColor: nextColor,
      movable: {
        color: nextColor,
        dests: this.getValidMoves()
      }
    });
  }

  /**
   * Calcule la carte des coups légaux requise par Chessground
   */
  private getValidMoves(): Map<Key, Key[]> {
    const dests = new Map<Key, Key[]>();
    this.chessGame.moves({ verbose: true }).forEach(m => {
      const fromKey = m.from as Key;
      const toKey = m.to as Key;

      if (dests.has(fromKey)) {
        dests.get(fromKey)!.push(toKey);
      } else {
        dests.set(fromKey, [toKey]);
      }
    });
    return dests;
  }

  /**
   * Envoie une question ouverte depuis la zone de chat
   */
  sendChatMessage(): void {
    if (!this.userInput.trim()) return;

    this.isLoading = true;
    this.errorMessage = "";
    const promptToSend = this.userInput;
    this.userInput = '';

    this.agentService.chatWithAgent(promptToSend).subscribe({
      next: (res: any) => {
        this.aiAnalysis = res.response;
        this.isLoading = false;
      },
      error: (err: any) => {
        console.error("Erreur de communication LLM :", err);
        this.errorMessage = "Impossible de joindre le Grand Maître FFE pour le moment.";
        this.isLoading = false;
      }
    });
  }
}
